import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Team {
  name: string;
  score: number;
}

interface KeyStat {
  stat: string;
  teamA: string;
  teamB: string;
}

interface MatchData {
  match: {
    teams: Team[];
    currentPeriod: string;
    timeRemaining: string;
    keyStats: KeyStat[];
  };
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const data = response.data as MatchData;
  const meta = response.meta as MetaData;
  const { teams, currentPeriod, timeRemaining, keyStats } = data.match;
  const [teamA, teamB] = teams;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1C1E26', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#4A90E2' }}>
              Live Sports Scores
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0B3B8', mt: 0.5 }}>
              {currentPeriod} - {timeRemaining} remaining
            </Typography>
          </Box>

          <Stack direction="row" justifyContent="space-between" alignItems="center">
            <Box>
              <Typography variant="body1" sx={{ color: '#D0021B', fontWeight: 'bold' }}>
                {teamA.name}
              </Typography>
              <Typography variant="h4" sx={{ color: '#F5A623', fontWeight: 'bold' }}>
                {teamA.score}
              </Typography>
            </Box>
            <Typography variant="h4" sx={{ color: '#4A90E2', fontWeight: 'bold' }}>
              VS
            </Typography>
            <Box textAlign="right">
              <Typography variant="body1" sx={{ color: '#D0021B', fontWeight: 'bold' }}>
                {teamB.name}
              </Typography>
              <Typography variant="h4" sx={{ color: '#50E3C2', fontWeight: 'bold' }}>
                {teamB.score}
              </Typography>
            </Box>
          </Stack>

          <Box>
            <Typography variant="body2" sx={{ color: '#B0B3B8', mb: 1 }}>
              Key Stats
            </Typography>
            <Stack spacing={0.5}>
              {keyStats.map((stat, index) => (
                <Stack key={index} direction="row" justifyContent="space-between" alignItems="center">
                  <Typography variant="body2" sx={{ color: '#FFFFFF' }}>{stat.stat}</Typography>
                  <Stack direction="row" spacing={1}>
                    <Chip label={stat.teamA} sx={{ bgcolor: '#4A90E2', color: '#FFFFFF', fontSize: '10px', px: 1 }} />
                    <Chip label={stat.teamB} sx={{ bgcolor: '#D0021B', color: '#FFFFFF', fontSize: '10px', px: 1 }} />
                  </Stack>
                </Stack>
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
